#![allow(
    clippy::unwrap_used,
    clippy::expect_used,
    clippy::doc_markdown,
    clippy::uninlined_format_args,
    clippy::indexing_slicing,
)]

use mqo_eval::{
    run::{run, OutputFormat, RunConfig},
    types::{OracleMode, Verdict},
};

/// Write an inline stub binder that echoes a fixed JSON payload — no
/// `mqo-agent` binary required.
fn write_stub_binder(dir: &tempfile::TempDir, answer: &str) -> String {
    use std::os::unix::fs::PermissionsExt;
    let path = dir.path().join("stub_binder.sh");
    let script = format!(
        "#!/bin/sh\n# CI stub binder — echoes a fixed bound-MQO JSON without calling mqo-agent.\necho '{{\"bound_mqo\":\"stub-mqo\",\"result_rows\":[[\"{answer}\"]],\"confidence\":0.95,\"pillars_fired\":[\"bind\",\"time_intel\"]}}'\n",
        answer = answer
    );
    std::fs::write(&path, script).expect("write stub binder");
    let mut perms = std::fs::metadata(&path).expect("metadata").permissions();
    perms.set_mode(0o755);
    std::fs::set_permissions(&path, perms).expect("set permissions");
    path.to_string_lossy().into_owned()
}

#[test]
fn acceptance_ac3() {
    let tmp = tempfile::tempdir().unwrap();
    let agent_cmd = write_stub_binder(&tmp, "hello");

    let q_path = tmp.path().join("q.yaml");
    std::fs::write(
        &q_path,
        "questions:\n  - id: q1\n    text: 'stub test'\n    expected_answer: 'hello'\n    model: tb/m\n",
    )
    .unwrap();
    let out = tmp.path().join("results.json");

    let cfg = RunConfig {
        questions_path: q_path.to_string_lossy().into_owned(),
        model: "tb/m".to_owned(),
        // Use the stub script instead of real mqo-agent.
        agent_cmd,
        oracle: OracleMode::Fixture,
        pg_host: None,
        pg_pass_env: "ATSCALE_PG_PASS".to_owned(),
        catalog_name: "atscale_catalogs".to_owned(),
        model_name: "tpcds_benchmark_model".to_owned(),
        max_result_rows: 50_000,
        pg_user: "atscale".to_owned(),
        out_path: out.to_string_lossy().into_owned(),
        format: OutputFormat::Text,
        results_dir: tmp.path().join("results").to_string_lossy().into_owned(),
    };

    let results = run(&cfg).expect("stub binder should work without real mqo-agent");
    assert_eq!(results.len(), 1);
    assert_eq!(
        results[0].verdict,
        Verdict::Correct,
        "stub returning expected answer should yield correct verdict"
    );
    // Pillars from stub should be captured.
    assert!(
        results[0].pillars_fired.contains(&"bind".to_owned()),
        "stub pillars should be captured in result"
    );
}
